import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public void processUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Validate user input to prevent XSS attacks
        if (userInput != null && !userInput.isEmpty()) {
            // Encode user input using HTML escaping to prevent script injection
            String encodedUserInput = StringEscapeUtils.escapeHtml4(userInput);

            // Output the sanitized user input
            response.getWriter().println("<p>User input: " + encodedUserInput + "</p>");
        } else {
            response.getWriter().println("<p>No user input provided</p>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
